import{c as e,Q as t,j as a,m as r}from"./chunks/framework.D9IbVcwA.js";const f=JSON.parse('{"title":"013-driver-vga-fb-1 · VGA 帧缓冲","description":"","frontmatter":{"title":"013-driver-vga-fb-1 · VGA 帧缓冲"},"headers":[],"relativePath":"hands-on/013-driver-vga-fb-1.md","filePath":"hands-on/013-driver-vga-fb-1.md","lastUpdated":1779686691000}'),i={name:"hands-on/013-driver-vga-fb-1.md"};function n(d,o,l,p,c,s){return t(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="_013-1-底座-线性帧缓冲区与-mmio-页表映射" tabindex="-1">013-1 底座：线性帧缓冲区与 MMIO 页表映射 <a class="header-anchor" href="#_013-1-底座-线性帧缓冲区与-mmio-页表映射" aria-label="Permalink to &quot;013-1 底座：线性帧缓冲区与 MMIO 页表映射&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>在上一章（012_driver_serial）中，我们搞定了串口驱动和 kprintf 的格式化输出，但内核到现在还只能通过串口 &quot;盲打&quot;——屏幕上什么都没有。这一章我们要把屏幕点亮：让内核获得对 VBE 线性帧缓冲区的直接控制权，能够在屏幕上画像素、填矩形、滚动画面。完成这一章后，你会看到 QEMU 窗口从一个黑屏变成可以编程控制像素的画布——虽然还不能写字，但那是下一章的事了。</p><p>这一章涉及两个关键问题：第一，bootloader 已经帮我们设好了 VBE 图形模式，但帧缓冲区的物理地址（通常是 0xE0000000 附近）不一定在内核的页表映射范围内，所以我们得自己扩展页表；第二，拿到映射后的地址之后，我们需要一套简洁的绘图原语来操作像素。</p><p>知识前置：你需要理解 x86_64 四级页表的基本结构（PDPT -&gt; PD -&gt; PT -&gt; Page），以及 VBE 线性帧缓冲区的工作原理（上一章 bootloader 中的 VESA 调用已经把模式设好了）。如果不清楚大页映射的概念，建议先回顾 tag 003 中 bootloader 建立初始页表的部分——本篇的 <code>map_mmio</code> 函数就是在那套页表基础上添加新条目。</p><h2 id="背景与动机" tabindex="-1">背景与动机 <a class="header-anchor" href="#背景与动机" aria-label="Permalink to &quot;背景与动机&quot;">​</a></h2><p>在 PC 的早期（VGA 时代），屏幕显示是通过文本模式实现的——显卡内置了一个字符发生器（character generator），你只需要往 0xB8000 处的显存写入字符编码和属性字节，硬件自动帮你把字符渲染成像素。这种模式非常方便，但分辨率被限制在 80x25 或者 132x50，而且不支持自定义字体和图形。</p><p>VBE（VESA BIOS Extensions）的出现改变了这一切——它允许软件把显卡切换到图形模式，直接操作一个线性帧缓冲区。在图形模式下，没有硬件字符发生器，没有自动换行，没有光标——一切都得自己实现。代价是更高的编程复杂度，好处是完全的自由度。</p><p>Cinux 选择图形模式而不是 VGA 文本模式，原因有三。第一，VGA 文本模式的分辨率太低（80x25），在 1024x768 的屏幕上显得非常粗糙。第二，文本模式只能显示 256 种预定义字符，无法渲染中文或自定义图形。第三，几乎所有现代 OS 都使用图形模式——学习图形模式的帧缓冲区编程更贴近实际。</p><h2 id="与其他系统的对比" tabindex="-1">与其他系统的对比 <a class="header-anchor" href="#与其他系统的对比" aria-label="Permalink to &quot;与其他系统的对比&quot;">​</a></h2><p>Linux 的帧缓冲区抽象（fbdev）比我们复杂得多——它支持多种像素格式（8bpp 调色板、16bpp RGB565、32bpp XRGB8888）、硬件加速操作（BitBLT、光标叠加）、以及双缓冲机制。Cinux 目前只支持 32bpp XRGB，但这个子集已经足够实现完整的控制台输出。</p><p>SerenityOS 的帧缓冲区驱动更接近 Cinux 的设计——直接通过 volatile 指针写入线性帧缓冲区，没有额外的抽象层。但 SerenityOS 的帧缓冲区是在 higher-half 的专用虚拟地址空间中映射的，而我们使用更简单的 identity mapping。</p><p>xv6 使用的是 VGA 文本模式（0xB8000），完全不需要页表映射和像素操作——CGA 控制器硬件自动处理字符渲染。这使得 xv6 的控制台代码非常简洁，但也限制了它只能显示 80x25 的文本。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="线性帧缓冲区-linear-framebuffer" tabindex="-1">线性帧缓冲区（Linear Framebuffer） <a class="header-anchor" href="#线性帧缓冲区-linear-framebuffer" aria-label="Permalink to &quot;线性帧缓冲区（Linear Framebuffer）&quot;">​</a></h3><p>VBE 2.0 以后，显卡可以提供一个连续的物理内存区域作为帧缓冲区。在这块内存里，每一个像素的颜色值被存储为一个固定长度的整数——在我们的场景中是 32 位（0x00RRGGBB 格式，每个通道 8 位）。屏幕上第 x 列、第 y 行的像素在内存中的位置是 <code>帧缓冲区基地址 + y * pitch + x * 4</code>，其中 pitch 是每行占用的字节数。</p><p>这里有一个很容易踩的坑：pitch 不一定等于 <code>width * bytes_per_pixel</code>。有些显卡会在每行末尾添加填充字节来对齐到某个边界。所以你必须用 bootloader 传递的 pitch 值来计算偏移，而不是自己算。OSDev Wiki 的 VESA BIOS Extensions 页面专门强调了这一点——很多新手用自己的 width * 4 来代替 pitch，在大多数情况下碰巧能工作，但遇到对齐要求不同的硬件就会出问题。</p><p>另一个常见误解是像素格式的字节序。在 Bochs/QEMU 中，32bpp 的像素格式是 XRGB（0x00RRGGBB），最高字节未使用。这与某些 ARM 平台的 BGRX 格式不同。如果你把红色通道写到了蓝色通道的位置，画面不会黑屏但颜色会全错——这种 bug 比&quot;完全不工作&quot;更难发现。</p><h3 id="mmio-映射与-huge-page" tabindex="-1">MMIO 映射与 Huge Page <a class="header-anchor" href="#mmio-映射与-huge-page" aria-label="Permalink to &quot;MMIO 映射与 Huge Page&quot;">​</a></h3><p>帧缓冲区的物理地址通常在高地址区域（Bochs 模拟器默认用 0xE0000000，即 3.5GB 处）。我们的 bootloader 在进入 long mode 时设置了一套基本的页表，只映射了前几 MB 的物理内存。所以访问帧缓冲区之前，必须先在页表中添加对应的映射。</p><p>一个 1024x768x32bpp 的帧缓冲区大约占 3MB（1024 * 768 * 4 = 3,145,728 字节）。用 2MB 大页（Huge Page）来映射的话只需要 2 个 PDE 项。如果物理地址超过 1GB 边界，还可以用 1GB 大页来映射，但需要先检查 CPU 是否支持（CPUID.80000001H:EDX bit 26）。</p><p>大页映射的好处是简单——只需要填充一个 PDE 或 PDPTE 条目，不需要创建完整的四级页表。对于 MMIO 设备来说，这完全够用了。PDE 中的标志位 0x83 表示 Present + Read/Write + Page Size（2MB 大页）。</p><p>为什么选择大页而不是普通的 4KB 页？两个原因。第一是效率——一个大页条目替代了 512 个 PT 条目，减少了页表占用的内存。第二是 TLB 利用率——一个大页只占一个 TLB 条目，而覆盖同样范围需要 512 个 4KB TLB 条目。帧缓冲区是频繁访问的区域（每次渲染字符都要写像素），TLB 命中率对性能有直接影响。</p><p>还有一个经常被忽略的细节：identity mapping 的选择。我们的 <code>map_mmio</code> 函数使用 identity mapping（虚拟地址 = 物理地址），这意味着映射后的虚拟地址直接等于帧缓冲区的物理地址。这在内核开发初期很方便——不需要维护额外的虚拟地址分配器。但 Linux 不这么做，Linux 用专门的 <code>ioremap()</code> 函数把 MMIO 区域映射到 higher-half 的专用虚拟地址范围，好处是不会与直接映射区域冲突，也更容易区分&quot;普通内存&quot;和&quot;设备内存&quot;。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-修改-vbe-模式号" tabindex="-1">Step 1: 修改 VBE 模式号 <a class="header-anchor" href="#step-1-修改-vbe-模式号" aria-label="Permalink to &quot;Step 1: 修改 VBE 模式号&quot;">​</a></h3><p><strong>目标</strong>: 将 bootloader 中的 VBE 模式从 0x118 切换到 0x144（Bochs VBE 变体），确保在 QEMU/Bochs 环境下兼容性更好。</p><p><strong>设计思路</strong>: 模式号 0x118 和 0x144 都表示 1024x768x32bpp，但不同模拟器的 VBE 实现可能只支持其中一种。Bochs 原生支持 0x144。模式号与 bit14（0x4000）组合后得到传给 INT 0x10 AX=0x4F02 的 BX 值：0x4144。</p><p>bit14（0x4000）这个标志的含义是&quot;请求线性帧缓冲区&quot;——如果不设置这个位，显卡可能使用 banked 模式（窗口切换模式），那意味着你需要通过 VBE 的窗口切换接口来访问帧缓冲区的不同区域，编程复杂度急剧上升。所以在调用 VBE set mode 时，务必设置这个位。</p><p><strong>实现约束</strong>: 在 bootloader 汇编文件中找到 VESA_TARGET_MODE 的定义位置和两个使用位置（vesa_get_mode_info 和 vesa_set_mode），将 0x0118/0x4118 替换为 0x0144/0x4144。三个位置必须保持一致。</p><p><strong>踩坑预警</strong>: 如果你只改了一个地方没改另外两个，VBE 调用会成功但模式设置可能失败，屏幕黑屏但内核还在跑——串口有输出但画面空白，这种 bug 很难定位。建议用一个 <code>.set</code> 伪指令定义 <code>VESA_TARGET_MODE</code>，所有引用都通过这个符号名进行，避免手动同步三个数字。</p><p><strong>验证</strong>: 修改后重新构建 bootloader 和内核，启动 QEMU。串口输出应该能看到 <code>[BIG] Framebuffer initialised: 1024x768 32bpp</code> 之类的信息。QEMU 窗口应该从文字模式变成黑色画面（因为我们还没画东西）。</p><h3 id="step-2-实现页表映射函数" tabindex="-1">Step 2: 实现页表映射函数 <a class="header-anchor" href="#step-2-实现页表映射函数" aria-label="Permalink to &quot;Step 2: 实现页表映射函数&quot;">​</a></h3><p><strong>目标</strong>: 编写一个 <code>map_mmio</code> 函数，能将任意物理地址范围映射到虚拟地址空间中（利用已有的 identity mapping）。</p><p><strong>设计思路</strong>: 我们的 bootloader 已经设置了 identity mapping（物理地址 = 虚拟地址）和 higher-half mapping。页表的虚拟地址是已知的常量（PD 在 0xFFFFFFFF80003000，PDPT 在 0xFFFFFFFF80002000）。函数需要：</p><ol><li>对于 1GB 以内的物理地址范围，填充 PD 中对应的 PDE 条目（2MB 大页，flags = 0x83）。</li><li>对于 1GB 以上的范围，填充 PDPT 中对应的 PDPTE 条目（1GB 大页，flags = 0x83），但先检查 CPU 是否支持 1GB 页。</li><li>每填充一个 PDE 后调用 <code>invlpg</code> 刷新 TLB；如果修改了 PDPT 则重新加载 CR3。</li></ol><p>需要两个辅助函数：一个用 CPUID 检查 1GB 页支持，一个重新加载 CR3 刷新全部 TLB。所有涉及的页表虚拟地址通过命名空间常量定义。</p><p>对于帧缓冲区来说，Bochs 默认的物理地址 0xE0000000（3.5GB）超出了 PD 覆盖的第一个 1GB 范围，所以会走第二部分的 1GB 大页映射路径。映射一个 1GB 大页条目就够了——帧缓冲区只有 3MB，远小于 1GB。</p><p><strong>实现约束</strong>: 函数签名为接收物理基地址和大小两个参数，返回 void。命名空间为 <code>cinux::arch</code>。PD 和 PDPT 的虚拟地址作为编译期常量定义在匿名命名空间中。PDE flags 使用 0x83（Present + R/W + PS），PDPT 1GB flags 同样是 0x83。每个 PDE 条目需要检查是否为空（避免覆盖已有映射）。函数不分配新页——只填充已有页表结构中的空条目。</p><p>物理地址在计算 PDE 索引之前需要对齐到 2MB 边界——因为大页必须对齐到自身大小。做法是 <code>phys &amp; ~(PAGE_2MB_SIZE - 1)</code>，把低位清零。类似地，1GB 大页需要对齐到 1GB 边界。</p><p><strong>踩坑预警</strong>: 千万别覆盖 PDPT[0]，因为那个条目指向我们的 PD，覆盖了等于把所有低地址映射全部干掉。还有，<code>invlpg</code> 指令的参数是一个地址（不是页号），它 invalidate 包含该地址的 TLB 条目。用 <code>__asm__ volatile(&quot;invlpg (%0)&quot; : : &quot;r&quot;(addr))</code> 的写法。</p><p><strong>验证</strong>: 在 kernel_main 中调用 <code>map_mmio(fb_phys, fb_size)</code> 后，尝试通过物理地址指针写入一个像素值，然后用 <code>get_pixel</code> 读回来验证。或者等 Step 3 的 framebuffer 测试。</p><h3 id="step-3-实现-framebuffer-类" tabindex="-1">Step 3: 实现 Framebuffer 类 <a class="header-anchor" href="#step-3-实现-framebuffer-类" aria-label="Permalink to &quot;Step 3: 实现 Framebuffer 类&quot;">​</a></h3><p><strong>目标</strong>: 创建一个 <code>Framebuffer</code> 类，提供基本的绘图原语。</p><p><strong>设计思路</strong>: Framebuffer 类在 <code>init</code> 时从 BootInfo 获取帧缓冲区的物理地址、宽度、高度、pitch 和 bpp。然后调用 <code>map_mmio</code> 映射这片物理内存。之后所有绘图操作直接通过一个 volatile 指针写入。内部存储四个成员变量：基地址指针（volatile uint32_t*）、宽度、高度、pitch。</p><p><code>init</code> 方法中帧缓冲区总大小的计算公式是 <code>pitch * height</code>，不是 <code>width * 4 * height</code>。这是因为 pitch 是&quot;每行的实际字节数&quot;，它可能大于 <code>width * 4</code>（如果行尾有对齐填充）。用 width 来计算会少映射一部分内存，访问行尾填充区域时触发 page fault。</p><p><strong>实现约束</strong>: 类放在 <code>cinux::drivers</code> 命名空间中。需要提供以下公开方法：</p><ul><li><code>init(const BootInfo&amp;)</code>: 从 BootInfo 提取参数并调用 map_mmio 映射帧缓冲区</li><li><code>put_pixel(uint32_t x, uint32_t y, uint32_t argb)</code>: 写入单个像素，需要做边界检查</li><li><code>get_pixel(uint32_t x, uint32_t y) const</code>: 读取单个像素用于验证，同样做边界检查</li><li><code>fill_rect(x, y, w, h, argb)</code>: 填充矩形区域，双层循环</li><li><code>scroll_up(lines, line_height, bg)</code>: 向上滚动指定像素行数，底部的空行用 bg 色填充</li><li><code>clear(argb = 0)</code>: 清屏</li></ul><p>关键计算公式：像素地址 = <code>addr_[y * (pitch_ / 4) + x]</code>，注意 pitch 是字节数所以除以 4 得到 uint32_t 的索引。scroll_up 用字节级别的逐字节拷贝（因为源和目标都是 volatile 指针，不能直接用 memmove），底部空行用 fill_rect 填充。</p><p>scroll_up 的两个参数需要特别注意语义：第一个参数 <code>lines</code> 是实际要滚动的像素行数，第二个参数 <code>line_height</code> 是底部要清空的区域高度。在控制台场景中，这两个值通常相等（都是字体高度），但分开设计提供了灵活性——比如你想滚动半行然后只清除半行。</p><p><strong>踩坑预警</strong>: 帧缓冲区指针必须声明为 <code>volatile uint32_t*</code>，否则编译器可能优化掉看似&quot;无用的&quot;写入操作。另外，<code>pitch_ / 4</code> 而不是 <code>width_</code>——这是一个经典的 bug 来源。</p><p><strong>验证</strong>: 编写测试代码（内核内测试）：清屏到某个颜色（比如 0x00AAAAAA），然后读回 (0,0)、(512,384)、(1023,767) 三个像素，验证是否都是那个颜色。put_pixel 写入 (100,100) 一个红色像素，读回验证。fill_rect 画一个 10x10 的绿色矩形，检查内部和边界外的像素。</p><h3 id="step-3-5-编写帧缓冲区测试" tabindex="-1">Step 3.5: 编写帧缓冲区测试 <a class="header-anchor" href="#step-3-5-编写帧缓冲区测试" aria-label="Permalink to &quot;Step 3.5: 编写帧缓冲区测试&quot;">​</a></h3><p><strong>目标</strong>: 在 <code>kernel/test/test_video.cpp</code> 中编写一组内核内测试，验证帧缓冲区的基本功能。</p><p><strong>设计思路</strong>: 内核内测试在 QEMU 中运行，可以访问真实的 VBE 帧缓冲区。测试分为几个独立的用例：初始化验证（从 BootInfo 读取的参数是否符合预期）、单像素读写验证（写入一个像素然后读回，确认值一致）、角落像素验证（检查 (0,0) 和 (1023,767) 这两个边界位置）、矩形填充验证（检查内部像素是填充色、外部像素保持不变）、清屏验证（检查三个采样点）、滚动验证（在一个位置画标记，滚动后检查标记是否移动了正确的距离）。</p><p><strong>实现约束</strong>: 测试文件需要 include framebuffer.hpp 和 boot_info.h。BootInfo 的物理地址常量定义为 0x7000。使用项目的 TEST_ASSERT_EQ 等宏。Framebuffer 和 PSFFont 声明为文件作用域的静态全局变量，供多个测试函数共享。每个测试函数独立运行，不依赖其他测试的状态。</p><p><strong>验证</strong>: 所有测试通过，确认帧缓冲区的基本绘图操作工作正常。如果某个测试失败，根据失败信息定位具体是哪个绘图原语有问题。</p><h3 id="step-3-6-理解-bootinfo-结构体" tabindex="-1">Step 3.6: 理解 BootInfo 结构体 <a class="header-anchor" href="#step-3-6-理解-bootinfo-结构体" aria-label="Permalink to &quot;Step 3.6: 理解 BootInfo 结构体&quot;">​</a></h3><p><strong>目标</strong>: 理解 BootInfo 结构体中与帧缓冲区相关的字段含义和来源。</p><p><strong>设计思路</strong>: BootInfo 是 bootloader 在 16 位实模式下通过 VBE 调用获取的信息，然后打包成一个结构体放在物理地址 0x7000。与帧缓冲区相关的字段有五个：<code>fb_addr</code>（帧缓冲区物理基地址，64 位）、<code>fb_width</code>（水平像素数）、<code>fb_height</code>（垂直像素数）、<code>fb_pitch</code>（每行字节数）、<code>fb_bpp</code>（每像素位数）。</p><p>这些数据来源于 VBE 的 ModeInfoBlock 结构体。bootloader 在调用 INT 0x10 AX=0x4F01（Get Mode Info）后，BIOS 返回一个结构体，其中 <code>PhysBasePtr</code> 字段就是帧缓冲区的物理地址，<code>XResolution</code>、<code>YResolution</code>、<code>LinBytesPerScanLine</code> 和 <code>BitsPerPixel</code> 分别对应宽高、pitch 和 bpp。bootloader 把这些值复制到 BootInfo 中传递给内核。</p><p><strong>踩坑预警</strong>: BootInfo 的内存布局必须与 bootloader 的写入顺序完全一致。如果 BootInfo 中字段的偏移量与 bootloader 代码中的偏移量不匹配，读到的数据就会错位——比如 fb_addr 可能读成了 fb_width 的值。这种情况不会崩溃（因为值仍然在合理范围内），但帧缓冲区初始化一定会失败。</p><h3 id="step-3-7-理解-volatile-语义与编译器优化" tabindex="-1">Step 3.7: 理解 volatile 语义与编译器优化 <a class="header-anchor" href="#step-3-7-理解-volatile-语义与编译器优化" aria-label="Permalink to &quot;Step 3.7: 理解 volatile 语义与编译器优化&quot;">​</a></h3><p><strong>目标</strong>: 理解为什么帧缓冲区指针必须声明为 volatile，以及编译器优化可能带来哪些问题。</p><p><strong>设计思路</strong>: <code>volatile</code> 关键字告诉编译器：&quot;这个内存位置的值可能在任何时候被外部因素修改，不要对它的读写做任何优化&quot;。对于帧缓冲区这种 MMIO 设备内存，这个语义至关重要。</p><p>编译器在没有 volatile 的情况下可能做的优化包括：把连续两次写入合并成一次（比如 put_pixel 两次写入同一个位置，编译器可能认为第一次写入是&quot;无用的&quot;就跳过了）、把写入后读取优化掉（编译器认为&quot;刚写入的值肯定等于写入的值&quot;就直接用寄存器里的值了）、把看似无用的写入完全删除（编译器认为这个地址没有人读取，写入就是浪费）。</p><p>这些优化在普通内存上是完全正确的——但帧缓冲区不是普通内存，它的&quot;读取者&quot;是显示器硬件。即使软件从不读取某个像素的值，写入操作仍然有副作用（屏幕上的像素改变了）。volatile 就是告诉编译器&quot;每个写入操作都有副作用，不能省略&quot;。</p><p>类似地，页表条目也是需要 volatile 的——因为页表的&quot;读取者&quot;是 CPU 的 MMU 硬件。如果你在页表中写入了一个新的 PDE 但编译器把这次写入优化掉了，MMU 永远看不到这个新条目，访问对应的虚拟地址就会触发 page fault。</p><p><strong>实现约束</strong>: addr_ 的类型必须是 <code>volatile uint32_t*</code>（指向 volatile uint32_t 的指针），不能是 <code>uint32_t* volatile</code>（volatile 的指针指向普通的 uint32_t）——前者表示指向的内存是 volatile 的，后者只是指针本身是 volatile 的。我们需要的是前者。</p><h3 id="step-4-在-kernel-main-中集成" tabindex="-1">Step 4: 在 kernel_main 中集成 <a class="header-anchor" href="#step-4-在-kernel-main-中集成" aria-label="Permalink to &quot;Step 4: 在 kernel_main 中集成&quot;">​</a></h3><p><strong>目标</strong>: 在 kernel_main 的初始化流程中，在串口/GDT/IDT/PIC/PIT 之后、中断使能之前初始化 Framebuffer。</p><p><strong>设计思路</strong>: BootInfo 结构体被 bootloader 放在物理地址 0x7000 处。由于我们的 identity mapping 覆盖了这个地址，可以直接将其 reinterpret_cast 为 <code>const BootInfo*</code> 来使用。Framebuffer 作为 kernel_main 的局部变量声明——它的生命周期就是内核的整个运行周期（因为 kernel_main 永远不会返回）。</p><p><strong>实现约束</strong>: 初始化顺序是固定的——Framebuffer 必须在 kprintf_init 之后（因为我们用 kprintf 打印初始化日志），在 Console 之前（Console 依赖 Framebuffer）。具体位置是：在 breakpoint 测试之后、IRQ0 unmask 之前。需要将 BootInfo 物理地址定义为编译期常量（0x7000）。</p><p><strong>验证</strong>: 启动 QEMU 后，串口输出应该包含 <code>[BIG] Framebuffer initialised: 1024x768 32bpp</code>。QEMU 窗口应该显示黑色画面（clear 默认填充 0）。如果 fb_addr 是 0 或者 bpp 是 0，说明 bootloader 的 VESA 调用失败了——回头看 bootloader 中 VESA mode info 的解析。</p><p><strong>进一步验证</strong>: 编写内核内测试代码——清屏到某个颜色（比如 0x00AAAAAA），然后读回三个位置的像素：左上角 (0,0)、中心 (512,384)、右下角 (1023,767)。三个像素都应该返回你设置的颜色。然后 put_pixel 写入 (100,100) 一个红色像素 (0x00FF0000)，读回验证。检查 (99,100) 和 (101,100) 是否仍然是清屏颜色——确认单个像素写入不会影响相邻像素。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>构建命令与之前相同。QEMU 启动后注意观察：窗口标题应该显示分辨率，如果分辨率不对说明 VBE 模式设置出了问题。串口输出中关于 framebuffer 的信息是第一手的诊断数据。</p><p>需要注意的是，VBE 模式切换发生在 bootloader 阶段（16 位实模式下通过 INT 0x10 调用），内核此时已经在 64 位长模式下运行——没有办法再调用 BIOS 中断了。所以帧缓冲区的配置完全依赖于 bootloader 传递过来的 BootInfo 数据。如果 BootInfo 里的数据不对，内核侧没有补救手段。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>帧缓冲区黑屏但串口正常</strong>: 先检查 map_mmio 是否真的被调用了（在 kprintf 中加日志），然后检查物理地址是否正确（从 BootInfo 读出来的 fb_addr 应该是类似 0xE0000000 的值）。如果 fb_addr 是 0，说明 bootloader 的 VESA 调用失败了。</p><p><strong>Triple fault 在 map_mmio 之后</strong>: 大概率是覆盖了 PDPT[0] 或者 PDE flags 写错了。用 GDB 在 map_mmio 处设断点，检查每个写入的 PDE 值。特别关注 PDPT 条目——如果你不小心写入了 PDPT[0]，所有低地址映射全部失效，连串口都访问不了。</p><p><strong>像素位置不对</strong>: 检查 pitch 是否正确。如果 pitch 为 0 或者是一个奇怪的值，说明 BootInfo 中的数据不正确——回头看 bootloader 中 VESA mode info 的解析。</p><p><strong>map_mmio 后帧缓冲区地址仍然触发 page fault</strong>: 可能是页表虚拟地址的常量值与 bootloader 实际设置的地址不匹配。检查 bootloader 代码中 PD 和 PDPT 被映射到的虚拟地址，确保与 <code>paging.cpp</code> 中的常量一致。另外确认 bootloader 的 higher-half 映射覆盖了 PD 和 PDPT 本身——如果页表本身没有被映射，你连访问页表都做不到。</p><p><strong>volatile 相关的诡异问题</strong>: 如果你能正常写入像素但读取时得到错误值（或者写入似乎没有生效），检查 addr_ 是否声明为 volatile uint32_t*。没有 volatile 的话，编译器在 -O2 以上可能会把&quot;看起来无用&quot;的写入操作优化掉。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>关键点</th></tr></thead><tbody><tr><td>线性帧缓冲区</td><td>物理地址 + y<em>pitch + x</em>4，pitch 可能大于 width*4</td></tr><tr><td>2MB Huge Page</td><td>PDE flags 0x83，覆盖 2MB 物理内存</td></tr><tr><td>1GB Huge Page</td><td>PDPTE flags 0x83，需要 CPUID 检查支持</td></tr><tr><td>volatile 指针</td><td>MMIO 必须用 volatile 防止编译器优化</td></tr><tr><td>VBE 模式号</td><td>0x144 + bit14(0x4000) = 0x4144 for Bochs</td></tr><tr><td>identity mapping</td><td>虚拟地址 = 物理地址，简单但不利于长期维护</td></tr></tbody></table><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><ul><li><strong>双缓冲（Double Buffering）</strong>: 分配一块与帧缓冲区同样大小的后备缓冲区，所有绘制操作先写到后备缓冲区，完成后一次性拷贝到前端。这能消除画面撕裂（tearing）现象——当滚动和绘制同时进行时，屏幕上半部分是旧内容、下半部分是新内容。难度：⭐⭐</li><li><strong>硬件加速 BitBLT</strong>: 如果模拟器支持 Bochs VBE Extensions 的虚拟显存操作，可以利用 <code>VBE_DISPI_INDEX_WIN</code> 等寄存器加速矩形填充和位块传输，避免逐像素的软件渲染。难度：⭐⭐⭐</li><li><strong>多分辨率支持</strong>: 从 BootInfo 动态读取分辨率和 bpp，支持 640x480、800x600、1920x1080 等多种模式。当前的 Framebuffer 类已经通过 BootInfo 参数化，理论上不需要改代码就能支持不同分辨率——但 Console 的行列数会随之变化。难度：⭐</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li>Intel SDM: Vol.3A Section 4.5 (4-Level Paging) -- 2MB page PDE format (Table 4-18), 1GB page PDPTE format (Table 4-16)</li><li>Intel SDM: Vol.3A Section 4.1.4 -- 1GB page support via CPUID.80000001H:EDX bit 26</li><li>OSDev Wiki: VESA BIOS Extensions -- ModeInfoBlock 字段说明、线性帧缓冲区</li><li>Linux fbdev: <code>drivers/video/fbdev/core/fbmem.c</code> 中使用 <code>fix.line_length * var.yres</code> 计算帧缓冲区大小</li><li>SerenityOS: <code>Kernel/Graphics/FramebufferConsole.h</code> 使用类似的 volatile 指针直接写入线性帧缓冲区</li><li>xv6: 使用 VGA 文本模式（0xB8000），不需要页表映射和像素操作</li></ul>',90)])])}const g=e(i,[["render",n]]);export{f as __pageData,g as default};
